void
yylexDoLex(LexerContext& lexerContext)
{
    switch (lexerContext.lexState) {
    case Initial:
        lexInitialState(lexerContext);
        break;
    case Scanning:
        lexScanningState(lexerContext);
        break;
    case SpecScan:
        lexUntermCharacterArray(lexerContext);
        break;
    }
}
